// diagnosisAndAutoRemediate walks through non-ready beads in the breakdown,
// diagnoses each one, and executes matching auto-remediations. Returns true
// if any remediation succeeded (caller should re-scan), false otherwise
// (caller should emit idle and sleep). Returns breakdown populated for caller use.
func diagnosisAndAutoRemediate(
	ctx context.Context,
	store ExecuteBeadLoopStore,
	breakdown *bead.ReadyExecutionBreakdown,
	runtime *ExecuteBeadLoopRuntime,
	emit func(string, map[string]any),
) error {
	diag, ok := store.(readyDiagnoser)
	if !ok {
		return nil
	}

	// Get the breakdown
	var bErr error
	*breakdown, bErr = diag.ReadyExecutionBreakdown()
	if bErr != nil {
		return fmt.Errorf("ReadyExecutionBreakdown: %w", bErr)
	}

	// Fetch all beads for building indexes
	allBeads, err := getAllBeadsForDiagnosis(store, ctx)
	if err != nil {
		return fmt.Errorf("getAllBeads: %w", err)
	}

	// Build indexes for diagnosis
	childIndex := buildChildIndex(allBeads)
	openChildIndex := buildOpenChildIndex(allBeads)
	depIndex := buildDepIndex(allBeads)

	// Track remediations
	var (
		remediationAttempts int
		remediationSuccess  int
	)

	// Walk non-ready beads and diagnose
	nonReadyIDs := append([]string{},
		breakdown.Epics...,
	)
	nonReadyIDs = append(nonReadyIDs, breakdown.EpicClosureCandidates...)
	nonReadyIDs = append(nonReadyIDs, breakdown.DependencyWaiting...)
	nonReadyIDs = append(nonReadyIDs, breakdown.ProposedOperatorAttention...)

	for _, beadID := range nonReadyIDs {
		b, ok := findBeadByID(allBeads, beadID)
		if !ok {
			continue
		}

		blockReason := bead.Diagnose(*b, childIndex, openChildIndex, depIndex)

		switch blockReason.Code {
		case bead.ReasonSupersededPendingClose:
			// The bead is superseded by a closed bead; cascade close will handle it
			remediationAttempts++
			if err := store.Close(ctx, beadID); err == nil {
				remediationSuccess++
			}

		case bead.ReasonClosureCandidateMisclassified:
			// Epic with all children closed; trigger closure path
			remediationAttempts++
			if err := store.Close(ctx, beadID); err == nil {
				remediationSuccess++
			}

		case bead.ReasonDeadIntermediateAllChildrenClosed:
			// Bead opted out of execution; all children closed; close it
			remediationAttempts++
			if err := store.Close(ctx, beadID); err == nil {
				remediationSuccess++
			}

		case bead.ReasonGenuinelyNeedsDecomposition:
			// Queue auto-decompose; only one per iteration
			remediationAttempts++
			// For now, skip auto-decompose in this phase
			// The autopsy of this case will be handled by a separate remediation phase

		default:
			// No immediate action: dep_blocked_by, parent_child_state_conflict,
			// claimed_in_progress, provider_route_unavailable, gated_by_budget_or_cooldown,
			// malformed_parent_or_dep_ref, dependency_cycle, closed_or_missing_parent,
			// auto_remediation_exhausted, no_diagnosis, stale_graph_index
		}
	}

	// If any remediation succeeded, emit event and signal re-scan
	if remediationSuccess > 0 {
		emit("loop.auto_remediated", map[string]any{
			"total_attempted": remediationAttempts,
			"total_succeeded": remediationSuccess,
			"reason":          "idle_path_auto_remediation",
		})
		return nil // Signal success (re-scan)
	}

	return nil
}

// getAllBeadsForDiagnosis fetches all beads from the store for diagnosis.
// It uses ReadyExecution as a fallback but attempts to get all beads first.
func getAllBeadsForDiagnosis(store ExecuteBeadLoopStore, ctx context.Context) ([]bead.Bead, error) {
	// Try to get all beads via ReadAll
	if readAllStore, ok := store.(interface{ ReadAll(context.Context) ([]bead.Bead, error) }); ok {
		if beads, err := readAllStore.ReadAll(ctx); err == nil {
			return beads, nil
		}
	}

	// Fallback to ReadyExecution
	if readyStore, ok := store.(interface{ ReadyExecution() ([]bead.Bead, error) }); ok {
		return readyStore.ReadyExecution()
	}

	return []bead.Bead{}, nil
}

// findBeadByID searches for a bead by ID in a slice of beads.
func findBeadByID(beads []bead.Bead, id string) (*bead.Bead, bool) {
	for i := range beads {
		if beads[i].ID == id {
			return &beads[i], true
		}
	}
	return nil, false
}

