		Title:  "Closed superseding bead",
		Status: bead.StatusClosed,
		Priority: 2,
	}
	require.NoError(t, store.Create(closedSuperseded))

	openLeftover := &bead.Bead{
		ID:     "ddx-superseded-leftover",
		Title:  "Open bead superseded by closed",
		Status: bead.StatusOpen,
		Labels: []string{"superseded-by:ddx-superseded-target"},
		Priority: 3,
	}
	require.NoError(t, store.Create(openLeftover))

	// Track emitted events
	var emittedEvents []map[string]any
	emit := func(eventType string, detail map[string]any) {
		detail["type"] = eventType
		emittedEvents = append(emittedEvents, detail)
	}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatalf("should not execute any bead: %s", beadID)
			return ExecuteBeadReport{}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

