		ID:       "ddx-epic-closure-child",
		Title:    "Closed child",
		Parent:   epic.ID,
		Status:   bead.StatusClosed,
		Priority: 1,
	}
	require.NoError(t, store.Create(child))

	// Create a supersession leftover: open bead with superseded-by pointing to closed bead
	closedSuperseded := &bead.Bead{
		ID:     "ddx-superseded-target",
		Title:  "Closed superseding bead",
		Status: bead.StatusClosed,
		Priority: 2,
	}
	require.NoError(t, store.Create(closedSuperseded))

	openLeftover := &bead.Bead{
		ID:     "ddx-superseded-leftover",
		Title:  "Open bead superseded by closed",
		Status: bead.StatusOpen,
		Labels: []string{"superseded-by:ddx-superseded-target"},
		Priority: 3,
	}
	require.NoError(t, store.Create(openLeftover))

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatalf("should not execute any bead: %s", beadID)
			return ExecuteBeadReport{}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	// Run the loop
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once: true,
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	// Verify both beads were closed by checking store state
	closedEpic, err := store.Get(context.Background(), epic.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, closedEpic.Status, "epic should be closed by remediation")

	closedLeftover, err := store.Get(context.Background(), openLeftover.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, closedLeftover.Status, "superseded bead should be closed by remediation")

	// Verify the result indicates no ready work
	assert.True(t, result.NoReadyWork, "should have no ready work after remediation")
}

