func TestWorkIdle_NoSuccessFallsThroughToSleep(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	// Create a bead with non-remediable diagnosis (e.g., dep-blocked-by)
	depBlocker := &bead.Bead{
		ID:     "ddx-blocker",
		Title:  "Blocking bead",
		Status: bead.StatusClosed,
		Priority: 1,
	}
	require.NoError(t, store.Create(depBlocker))

	depBlocked := &bead.Bead{
		ID:       "ddx-blocked",
		Title:    "Blocked bead",
		Status:   bead.StatusOpen,
		Priority: 0,
		Dependencies: []bead.Dependency{
			{
				DependsOnID: depBlocker.ID,
			},
		},
	}
	require.NoError(t, store.Create(depBlocked))

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatalf("should not execute any bead: %s", beadID)
			return ExecuteBeadReport{}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)
	require.NotNil(t, result)

	// Should report no ready work and include the blocked bead in dependency waiting
	assert.True(t, result.NoReadyWork)
	assert.Contains(t, result.NoReadyWorkDetail.DependencyWaiting, depBlocked.ID)
}

